{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시각",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스",
        "condition": "스모크 테스트 통과"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "mismatch 발생 시 먼저 패키지 설정을 점검하고, 계약(contract) 자체가 잘못된 경우에만 스크립트 검토"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "status": "내부 스트레치 목표(확정 일정 아님)"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 진행 의견만 있었고 확정 소유자 없음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로",
        "impact": "릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계 최신성 저하",
        "impact": "릴리스 노트가 사용자에게 오해를 줄 가능성"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미결정"
      },
      {
        "question": "릴리스 노트에 수요일 내부 스트레치 목표를 명시할 것인가?",
        "status": "미결정"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "선행 작업 대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(권고, 확정 아님)",
      "status": "소유자 미지정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun 스모크 테스트 결과(통과/실패 및 근거) 확인",
      "Doyun 실패 트리아지 노트 작성 완료 여부 확인",
      "Hara의 tarball 경로 점검 결과 확인",
      "최종 릴리스 승인 권한자 지정 여부 결정",
      "릴리스 노트에 수요일 내부 스트레치 목표 기재 여부 결정",
      "README 설치 단계 최신성 검토 소유자 지정"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 소유자/미합의 마감시각의 임의 확정"
    ]
  },
  "non_invention_rules": {
    "allowed_source": "inline public-safe synthetic fixture only",
    "forbidden_inventions": [
      "customer facts",
      "budget facts",
      "security incident facts",
      "outage facts",
      "legal requirement facts",
      "unassigned owner facts",
      "undecided deadline facts"
    ],
    "fact_boundary": [
      "확정 결정과 반려안, 스트레치 목표, 리스크, 오픈 질문을 분리 기록",
      "미결정 사항은 미결정으로 유지",
      "조건부 결정은 조건을 함께 명시"
    ]
  }
}
